'use strict';

// CSV line parser. See docs/rows.md for the contract and docs/conventions.md
// for the field rules (quoted fields unwrapped, embedded commas preserved,
// "" unescaped to ", no trimming).
//
// Returns an array of decoded field strings. Pure: no mutation, no I/O.
function parseCsvLine(line) {
  const fields = [];
  let i = 0;
  let afterComma = true;

  while (i < line.length || afterComma) {
    if (i >= line.length) {
      fields.push('');
      break;
    }

    afterComma = false;

    if (line[i] === '"') {
      let field = '';
      i++;
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++;
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      fields.push(field);
      if (i < line.length && line[i] === ',') {
        i++;
        afterComma = true;
      }
    } else {
      const start = i;
      while (i < line.length && line[i] !== ',') i++;
      fields.push(line.slice(start, i));
      if (i < line.length) {
        i++;
        afterComma = true;
      }
    }
  }

  return fields;
}

module.exports = { parseCsvLine };

