'use strict';
const { parseCsvLine } = require('./src/core/csv');
const eq = (a, b) => JSON.stringify(a) === JSON.stringify(b);
const tests = [
  ['id,name,role',        ['id', 'name', 'role']],
  ['"a,b",c',             ['a,b', 'c']],
  ['"she said ""hi"""',   ['she said "hi"']],
  ['a , b',               ['a ', ' b']],
  ['',                    ['']],
  ['a,b,',                ['a', 'b', '']],
  ['"",a',                ['', 'a']],
  ['a,"b""c"',            ['a', 'b"c']],
];
let pass = 0, fail = 0;
for (const [input, expected] of tests) {
  const result = parseCsvLine(input);
  const ok = eq(result, expected);
  console.log((ok ? 'PASS' : 'FAIL') + ': ' + JSON.stringify(input));
  if (!ok) console.log('  got:      ' + JSON.stringify(result) + '\n  expected: ' + JSON.stringify(expected));
  ok ? pass++ : fail++;
}
console.log(pass + '/' + (pass + fail) + ' passed');
process.exit(fail ? 1 : 0);

